overrides-wheels.nix { pkgs }:
_final: prev: { # Wheels are automatically patched using autoPatchelfHook. # # For manylinux wheels the appropriate packages are added # as described in https://peps.python.org/pep-0599/ and various other PEPs. # # Some packages provide binary libraries as a part of their binary wheels, # others expect libraries to be provided by the system. # # Numba depends on libtbb, of a more recent version than nixpkgs provides in it's default tbb attribute. numba = prev.numba.overrideAttrs (old: { buildInputs = (old.buildInputs or [ ]) ++ [ pkgs.tbb_2021_11 ]; }); } Long term this situation could be improved by PEP-725 . pyproject.toml [project]
name = "overriding"
version = "0.1.0"
description = "Show how to override dependencies"
readme = "README.md"
authors = [ { name = "adisbladis", email = "adisbladis@gmail.com" }
]
requires-python = ">=3.12"
dependencies = [ "numba>=0.60.0", "pyzmq>=26.2.0",
] [project.scripts]
overriding = "overriding:main" [build-system]
requires = ["hatchling"]
build-backend = "hatchling.build" [tool.uv]
no-binary-package = [ "pyzmq" # Force source builds
] flake.nix { description = "Uv2nix overriding example"; inputs = { nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable"; pyproject-nix = { url = "github:nix-community/pyproject.nix"; inputs.nixpkgs.follows = "nixpkgs"; }; uv2nix = { url = "github:adisbladis/uv2nix"; inputs.pyproject-nix.follows = "pyproject-nix"; inputs.nixpkgs.follows = "nixpkgs"; }; }; outputs = { nixpkgs, uv2nix, pyproject-nix, ... }: let inherit (nixpkgs) lib; forAllSystems = lib.genAttrs lib.systems.flakeExposed; workspace = uv2nix.lib.workspace.loadWorkspace { workspaceRoot = ./.; }; overlay = workspace.mkPyprojectOverlay { sourcePreference = "wheel"; }; pythonSets = forAllSystems ( system: let pkgs = nixpkgs.legacyPackages.${system}; baseSet = pkgs.callPackage pyproject-nix.build.packages { python = pkgs.python312; }; overlays = [ overlay # Note: Files are only split for documentation structuring purposes. # This is not considered a best practice. (import ./overrides-sdist.nix { inherit pkgs; }) (import ./overrides-wheels.nix { inherit pkgs; }) ]; in baseSet.overrideScope (lib.composeManyExtensions overlays) ); in { packages = forAllSystems ( system: let pythonSet = pythonSets.${system}; in { default = pythonSet.mkVirtualEnv "overriding-env" workspace.deps.default; } ); };
}
